def context_recall(needed, retrieved_text):
    hits = sum(1 for f in needed if f.lower() in retrieved_text.lower())
    return hits / len(needed)

def hit_rate_at_k(gold_id, ranked_ids, k):
    return 1.0 if gold_id in ranked_ids[:k] else 0.0

