import json

JUDGE = '''Given CONTEXT and a CLAIM, answer strict JSON:
{"supported": true|false}. CONTEXT:\n{ctx}\nCLAIM: {claim}'''

def faithfulness(claims, ctx, llm):
    ok = 0
    for c in claims:
        out = llm(JUDGE.format(ctx=ctx, claim=c))
        ok += 1 if json.loads(out)["supported"] else 0
    return ok / len(claims)

# claims = ["refund window is 30 days"] -> 1/1 = 1.0

def run_rag(q, retriever, llm, k=4):
    chunks = retriever.search(q, k=k)            # list[str]
    context = "\n".join(chunks)
    prompt = f"Answer ONLY from context.\n{context}\nQ: {q}"
    answer = llm(prompt)
    return {"retrieved_contexts": chunks, "answer": answer}

for row in evalset:
    row.update(run_rag(row["question"], retriever, llm))

def context_recall(truth, chunks):
    text = " ".join(chunks).lower()
    facts = [w for w in truth.lower().split() if len(w) > 3]
    hit = sum(1 for f in facts if f in text)
    return hit / max(len(facts), 1)

for row in evalset:
    row["recall"] = context_recall(
        row["ground_truth"], row["retrieved_contexts"])
print("avg recall:",
      sum(r["recall"] for r in evalset) / len(evalset))

THRESHOLDS = {"faithfulness": 0.85, "context_recall": 0.80}

def gate(report):
    failures = [m for m, lo in THRESHOLDS.items()
                if report[m] < lo]
    if failures:
        raise SystemExit(f"RAG quality regressed: {failures}")
    print("RAG eval passed \u2713")

gate(report)  # run in CI on every PR that touches retrieval
